using System;
using System.Diagnostics;
using System.Runtime.CompilerServices;
using System.Threading;
using SkiaSharp;

Console.WriteLine($"SkiaSharp Version: {typeof(SKCanvas).Assembly.GetName().Version}");
Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");

// Test 1: Verify GC can collect unreferenced SkiaSharp objects
var (weakRef, handle) = CreateAndTrackObject();
GC.Collect(2, GCCollectionMode.Forced, blocking: true);
GC.WaitForPendingFinalizers();
GC.Collect(2, GCCollectionMode.Forced, blocking: true);
bool wasCollected = !weakRef.TryGetTarget(out _);
Console.WriteLine($"Object collected: {wasCollected}");
if (wasCollected)
    Console.WriteLine($"VULNERABLE: Handle extracted but object collected.");

[MethodImpl(MethodImplOptions.NoInlining)]
static (WeakReference<SKPaint>, IntPtr) CreateAndTrackObject()
{
    var p = new SKPaint();
    var h = p.Handle;
    var w = new WeakReference<SKPaint>(p);
    return (w, h);
}
